// Master Router POSTs the events row body. Pull payload, verify shape.
// Pipeline 2 trigger event is `invoice.detected` from gmail-ingest-v1,
// payload contains: gmail_message_id, email_id, source='email', entity_id.
// Attachment metadata (filename, mime_type, attachment_id) is NOT in this
// event — gmail-ingest-v1 emits it separately as document.received. So
// we look up the most recent unprocessed attachment for this email and
// process it. If multiple attachments, the workflow will fire once per
// document.received event via P9; this pipeline targets the *invoice*
// classification specifically.
const raw = $input.first().json;
const body = raw.body || raw;
const payload = (body.payload && typeof body.payload === 'object')
  ? body.payload
  : (typeof body.payload === 'string' ? JSON.parse(body.payload) : {});

const event_id  = body.id || raw.id;
const trace_id  = body.trace_id || raw.trace_id;
const gmail_message_id = payload.gmail_message_id;
const email_id  = payload.email_id ?? null;
const entity_id = payload.entity_id ?? null;
const account   = payload.account || 'personal1';

if (!event_id)         throw new Error('missing event id');
if (!trace_id)         throw new Error('missing trace_id');
if (!gmail_message_id) throw new Error('payload missing gmail_message_id');
if (!entity_id)        throw new Error('payload missing entity_id (from email classifier)');

return [{ json: { event_id, trace_id, gmail_message_id, email_id, entity_id, account } }];

// Combine validate-event context with the attachment metadata; pick the
// right downstream extractor (pdfplumber for PDFs, MarkItDown for everything
// else MarkItDown handles — image/Word/HTML/etc).
const v = $('Validate Event').first().json;
const att = $input.first().json;
if (!att.attachment_id) {
  throw new Error(`no document.received event found for ${v.gmail_message_id} — invoice has no attachment to extract`);
}
const mime = String(att.mime_type || '').toLowerCase();
const filename = String(att.filename || '').toLowerCase();
let extractor_url;
if (mime === 'application/pdf' || filename.endsWith('.pdf')) {
  extractor_url = 'http://homeai-pdfplumber:8003/extract-pdf';
} else {
  extractor_url = 'http://homeai-markitdown:8004/convert';
}
return [{ json: { ...v, ...att, extractor_url } }];

const att = $input.first().json;
if (!att.data) throw new Error('Gmail attachment fetch returned no data');
const b64 = att.data.replace(/-/g, '+').replace(/_/g, '/');
const pad = b64.length % 4;
const b64padded = pad ? b64 + '='.repeat(4 - pad) : b64;
const buffer = Buffer.from(b64padded, 'base64');
if (buffer.length > 25 * 1024 * 1024) {
  throw new Error(`attachment too large: ${buffer.length} bytes`);
}
const v = $('Merge Attachment Meta').first().json;
return [{
  json: { ...v, attachment_size: buffer.length },
  binary: { file: { data: buffer.toString('base64'), fileName: v.filename, mimeType: v.mime_type } }
}];

// pdfplumber returns {text, content_hash}, MarkItDown returns the same.
// Sanitise + cap to keep prompt + cost in line.
const out = $input.first().json;
let text = String(out.text || '').replace(/[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]/g, '').slice(0, 8000);
const v = $('Decode + Build Form').first().json;
return [{ json: { ...v, extracted_text: text, content_hash: out.content_hash || null } }];

const item = $input.first().json;
const v = $('Build Extractor Prompt').first().json;

let ai;
try {
  const text = item.content?.[0]?.text || '{}';
  ai = JSON.parse(text);
} catch (e) {
  ai = { supplier_name: null, invoice_number: null, invoice_date: null,
         due_date: null, gross_amount: 0, net_amount: null, vat_amount: null,
         currency: 'GBP', category: 'other', confidence_score: 0,
         requires_human: true, reasoning: 'parse error' };
}

// Coerce + bound
const gross = Number(ai.gross_amount) || 0;
const net   = ai.net_amount   == null ? null : Number(ai.net_amount);
const vat   = ai.vat_amount   == null ? null : Number(ai.vat_amount);
const confidence = Math.min(1, Math.max(0, Number(ai.confidence_score) || 0));
const supplier = String(ai.supplier_name || '').slice(0, 200).trim();
const invoice_date = (ai.invoice_date && /^\d{4}-\d{2}-\d{2}$/.test(ai.invoice_date)) ? ai.invoice_date : null;
const due_date     = (ai.due_date     && /^\d{4}-\d{2}-\d{2}$/.test(ai.due_date))     ? ai.due_date     : null;

const min_conf = 0.85;  // SPEC §6.2 P2 default — adjust per ai.thresholds.invoice_extractor
const status = confidence >= min_conf
  ? 'success'
  : confidence >= min_conf * 0.85
    ? 'escalate'
    : 'fail';

const outcome = {
  status,
  confidence,
  reasoning: String(ai.reasoning || '').slice(0, 1000),
  data: { supplier_name: supplier, invoice_number: ai.invoice_number || null,
          invoice_date, due_date, gross_amount: gross, net_amount: net,
          vat_amount: vat, currency: ai.currency || 'GBP',
          category: ai.category || 'other' },
  requires_human: status === 'fail' || !!ai.requires_human || !supplier || !invoice_date || !gross,
  worker: 'invoice_extractor',
  tier_used: 'haiku'
};

// Idempotency per the rewritten SPEC §6.2 P2:
// invoice_{sha256(supplier_name+gross_amount+invoice_date+entity_id)}
const crypto = require('crypto');
const keyRaw = `${supplier}|${gross.toFixed(2)}|${invoice_date || ''}|${v.entity_id}`;
const keyHash = crypto.createHash('sha256').update(keyRaw).digest('hex');
const idem_key = 'invoice_' + keyHash;

// Sign the invoice.extracted/unmatched payload
const signing_key = $('Vault: Signing Key').first().json.data.data.payload_hmac_key;
const eventPayload = {
  invoice_idempotency_key: idem_key,
  supplier_name: supplier,
  invoice_number: ai.invoice_number || null,
  invoice_date,
  gross_amount: gross,
  entity_id: v.entity_id,
  email_id: v.email_id,
  gmail_message_id: v.gmail_message_id,
  filename: v.filename
};
const canonical = JSON.stringify(eventPayload, Object.keys(eventPayload).sort());
const signature = crypto.createHmac('sha256', signing_key).update(canonical).digest('hex');

// Pipeline 2 emits invoice.extracted on success, invoice.unmatched on
// requires_human (Phase 1 — Xero match step is stubbed, emit unmatched
// for everything until P3 exists).
const out_event_type = outcome.requires_human ? 'invoice.unmatched' : 'invoice.unmatched';
// ^ keep both branches as 'invoice.unmatched' for now — when P3 (Xero) is
//   added, success path becomes 'invoice.extracted' once a match succeeds.

return [{
  json: {
    ...v,
    outcome,
    outcome_json: JSON.stringify(outcome),
    idempotency_key: idem_key,
    supplier_name: supplier,
    invoice_number: ai.invoice_number || null,
    invoice_date,
    due_date,
    gross_amount: gross,
    net_amount: net,
    vat_amount: vat,
    currency: ai.currency || 'GBP',
    category: ai.category || 'other',
    confidence,
    requires_human: outcome.requires_human,
    out_event_type,
    out_event_payload_json: JSON.stringify(eventPayload),
    out_event_signature: signature,
    out_event_idem_key: 'invoice_event_' + keyHash,
    ai_raw: JSON.stringify(item.content || item)
  }
}];
